// TestRegisterCommand_Concurrent tests thread-safety of registration
func TestRegisterCommand_Concurrent(t *testing.T) {
	ClearGlobalCommands()
	defer ClearGlobalCommands()

	const n = 100
	results := make(chan error, n)

	var wg sync.WaitGroup
	wg.Add(n)

	// Try to register 100 commands with the same name concurrently
	for i := 0; i < n; i++ {
		go func(idx int) {
			defer wg.Done()
			executor := newMockExecutor(`^/test$`, "", false)
			err := RegisterCommand("contested", executor)
			results <- err
		}(i)
	}

	wg.Wait()
	close(results)

	// Exactly one registration should succeed, rest should fail
	var successes, failures int
	for err := range results {
		if err == nil {
			successes++
		} else {
			failures++
			assert.Contains(t, err.Error(), "already registered")
		}
	}

	assert.Equal(t, 1, successes, "exactly one registration should succeed")
	assert.Equal(t, n-1, failures, "all other registrations should fail")

	// Verify only one command is registered
	commands := ListRegisteredCommands()
	assert.Len(t, commands, 1)
}

