// TestCommandContext_RespectsContext tests that CommandContext respects context cancellation
func TestCommandContext_RespectsContext(t *testing.T) {
	executor := newMockExecutor(`^/test$`, "", false)

	ctx, cancel := context.WithCancel(context.Background())
	cancel() // Cancel immediately

	cmdCtx := &CommandContext{
		LoopTracker: NewLoopTracker(),
	}

	msg := agentic.UserMessage{
		MessageID:   "msg-1",
		ChannelType: "cli",
		ChannelID:   "test",
		UserID:      "user-1",
	}

	// Mock executor doesn't check context.Done(), but real implementations should
	// This test documents the expectation
	_, _ = executor.Execute(ctx, cmdCtx, msg, []string{}, "")

	// Real implementations should check ctx.Done() and return early if cancelled
	assert.Equal(t, context.Canceled, ctx.Err())
}

